import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Field, FieldError, FieldGroup, FieldLabel } from '@/components/ui/field';
import { Input } from '@/components/ui/input';

import { Controller, useFormContext } from 'react-hook-form';
import { employeeFormSchemaType } from '../EmployeeCreateUpdateForm';

const UserCredentials = () => {
  const { control } = useFormContext<employeeFormSchemaType>();
  return (
    <Card>
      <CardHeader>
        <CardTitle>User Credentials</CardTitle>
      </CardHeader>
      <CardContent>
        <FieldGroup>
          <Controller
            control={control}
            name='userCredentials.name'
            render={({ field, fieldState }) => (
              <Field>
                <FieldLabel>Name</FieldLabel>
                <Input placeholder='Enter Name' {...field} />
                {fieldState?.invalid && (
                  <FieldError errors={[fieldState?.error, fieldState?.error?.root]} />
                )}
              </Field>
            )}
          />
          <Controller
            control={control}
            name='userCredentials.email'
            render={({ field, fieldState }) => (
              <Field>
                <FieldLabel>Email</FieldLabel>
                <Input placeholder='Enter Email' {...field} />
                {fieldState?.invalid && (
                  <FieldError errors={[fieldState?.error, fieldState?.error?.root]} />
                )}
              </Field>
            )}
          />
          <Controller
            control={control}
            name='personalEmail'
            render={({ field, fieldState }) => (
              <Field>
                <FieldLabel>Personal Email</FieldLabel>
                <Input placeholder='Enter Personal Email' {...field} />
                {fieldState?.invalid && (
                  <FieldError errors={[fieldState?.error, fieldState?.error?.root]} />
                )}
              </Field>
            )}
          />
        </FieldGroup>
      </CardContent>
    </Card>
  );
};

export default UserCredentials;
